class Solution(object):
    def minimumChanges(self, s, k):
        """
        :type s: str
        :type k: int
        :rtype: int
        """
        n = len(s)

        def get_divisors(length):
            """Get proper divisors of length (excluding 1 and length)"""
            if length < 2:
                return []
            divisors = []
            for d in range(2, length):
                if length % d == 0:
                    divisors.append(d)
            return divisors

        def min_changes_to_semi_palindrome(substring):
            """Calculate minimum changes to make substring a semi-palindrome"""
            length = len(substring)
            if length < 2:
                return 0

            divisors = get_divisors(length)
            if not divisors:
                return float('inf')  # No valid divisor

            min_changes = float('inf')

            for d in divisors:
                # Check if this divisor works
                groups = [[] for _ in range(d)]

                # Group characters by position mod d
                for i in range(length):
                    groups[i % d].append(substring[i])

                # Count changes for each group to be palindrome
                changes = 0
                for group in groups:
                    # Make group a palindrome
                    for i in range(len(group) // 2):
                        if group[i] != group[len(group) - 1 - i]:
                            changes += 1

                min_changes = min(min_changes, changes)

            return min_changes

        # Precompute cost to convert each substring to semi-palindrome
        cost = [[0] * n for _ in range(n)]

        for i in range(n):
            for j in range(i, n):
                substring = s[i:j+1]
                cost[i][j] = min_changes_to_semi_palindrome(substring)

        # DP: dp[i][j] = min changes to split s[0:i] into j semi-palindromes
        INF = float('inf')
        dp = [[INF] * (k + 1) for _ in range(n + 1)]
        dp[0][0] = 0

        for i in range(1, n + 1):
            for j in range(1, min(i, k) + 1):
                # Try all starting positions for the j-th substring
                for start in range(j - 1, i):
                    if dp[start][j - 1] != INF:
                        # j-th substring is s[start:i]
                        substring_cost = cost[start][i - 1]
                        if substring_cost != INF:
                            dp[i][j] = min(dp[i][j], dp[start][j - 1] + substring_cost)

        return dp[n][k]
